package com.pqc.core.security;
import com.pqc.core.entity.*; import com.pqc.core.repository.UserRepository; import org.junit.jupiter.api.*; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.boot.test.context.SpringBootTest; import org.springframework.boot.webmvc.test.autoconfigure.AutoConfigureMockMvc; import org.springframework.http.MediaType; import org.springframework.jdbc.core.JdbcTemplate; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.test.context.ActiveProfiles; import org.springframework.test.web.servlet.MockMvc; import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*; import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@SpringBootTest @AutoConfigureMockMvc @ActiveProfiles("test") class MarketingAdminControllerTest {@Autowired MockMvc mvc;@Autowired UserRepository users;@Autowired PasswordEncoder encoder;@Autowired JwtService jwt;@Autowired JdbcTemplate jdbc;User admin;@BeforeEach void setup(){jdbc.execute("SET REFERENTIAL_INTEGRITY FALSE");for(String t:new String[]{"marketing_notifications","marketing_banners","marketing_campaigns","offers","plumber_kyc","support_messages","support_tickets","refund_requests","settlements","outbox_events","inventory_reservations","product_order_items","product_orders","service_orders","stocks","stores","user_addresses","wallet_transactions","wallets","refresh_tokens","notifications","users"})try{jdbc.execute("TRUNCATE TABLE "+t+" RESTART IDENTITY");}catch(Exception ignored){}jdbc.execute("SET REFERENTIAL_INTEGRITY TRUE");admin=users.save(User.builder().email("marketing@test").password(encoder.encode("x")).fullName("Marketing").phone("99").role(Role.MARKETING_ADMIN).status(UserStatus.ACTIVE).build());}
@Test void createsMarketingResources()throws Exception{String a=bearer();mvc.perform(post("/api/v1/admin/marketing/offers").header("Authorization",a).contentType(MediaType.APPLICATION_JSON).content("{\"code\":\"FIRST50\",\"title\":\"First\",\"discountType\":\"PERCENTAGE\",\"discountValue\":50,\"minOrderAmount\":199,\"startsAt\":\"2026-01-01T00:00:00\",\"endsAt\":\"2026-12-31T23:59:59\"}")).andExpect(status().isOk()).andExpect(jsonPath("$.code").value("FIRST50"));mvc.perform(post("/api/v1/admin/marketing/campaigns").header("Authorization",a).contentType(MediaType.APPLICATION_JSON).content("{\"name\":\"Weekend\",\"campaignType\":\"PUSH\",\"targetSegment\":\"CUSTOMERS\"}")).andExpect(status().isOk());mvc.perform(post("/api/v1/admin/marketing/banners").header("Authorization",a).contentType(MediaType.APPLICATION_JSON).content("{\"title\":\"Sale\",\"placement\":\"CUSTOMER_HOME\"}")).andExpect(status().isOk());mvc.perform(post("/api/v1/admin/marketing/notifications/send").header("Authorization",a).contentType(MediaType.APPLICATION_JSON).content("{\"title\":\"Sale\",\"message\":\"Today only\",\"targetSegment\":\"CUSTOMERS\"}")).andExpect(status().isOk()).andExpect(jsonPath("$.status").value("SENT"));}private String bearer(){return "Bearer "+jwt.generateToken(admin.getEmail(),admin.getRole().name());}}
